class Solution {
public:
    bool isAnagram(const string& s, const string& t) {
        if (s.length() != t.length()) {
            return false;
        }
        string sPerm = s;
        sort(sPerm.begin(), sPerm.end());
        string tPerm = t;
        sort(tPerm.begin(), tPerm.end());
        return sPerm == tPerm;
    }
};

