public class Solution {
    public bool isAnagram(string s, string t) {
        if (s.Length != t.Length) return false;
        var permutations = GetPermutations(s);
        foreach (var perm in permutations) {
            if (perm == t) return true;
        }
        return false;
    }

    private List<string> GetPermutations(string str) {
        if (str.Length == 1) return new List<string> { str };
        var result = new List<string>();
        foreach (var c in str) {
            var remaining = str.Replace(c.ToString(), string.Empty);
            foreach (var perm in GetPermutations(remaining)) {
                result.Add(c + perm);
            }
        }
        return result.Distinct().ToList();
    }
}

