#include <vector>
#include <string>
#include <unordered_map>
using namespace std;

class Solution {
public:
    bool isAnagram(const string& s, const string& t) {
        if (s.size() != t.size()) return false;
        unordered_map<char, int> count;

        for (char c : s) {
            count[c]++;
        }

        for (char c : t) {
            if (count[c] == 0) return false;
            count[c]--;
        }

        return true;
    }
};

